INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('pukao-64311456-moex-00258', 'pukao-64311456', 'pukao-64311456-moex-112-e718b90b', 'sub-pukao-64311456-02', NULL, 'single_choice', '關於請領老年給付或退休金之年齡標準，下列敘述何者錯誤？', '["請領國民年金老年年金給付，必須年滿65歲", "依勞工保險條例第58條規定，年滿60歲有保險年資者，得請領勞工保險老年給付，但自民國97 年7月17日修正之條文施行之日起，第10年提高1歲，其後每2年提高1歲，以提高至65歲為限", "依勞工退休金條例第24條，勞工年滿65歲，得依下列規定之方式請領退休金：一、工作年資滿 15年以上者，選擇請領月退休金或一次退休金。二、工作年資未滿15年者，請領一次退休金", "老年農民福利津貼之請領年齡，必須年滿65歲"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:34+00:00", "source_pdf_sha1": "c98749f6e262", "answer_pdf_sha1": "d120e8b33bc5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "405", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "社會行政"}'::jsonb, NULL),
  ('pukao-64311456-moex-00259', 'pukao-64311456', 'pukao-64311456-moex-112-e718b90b', 'sub-pukao-64311456-02', NULL, 'single_choice', '關於近年來職業退休金相關立法的發展，下列描述何者錯誤？', '["民國111年三讀通過之公務人員個人專戶制退休資遣撫卹法規定，其適用對象為民國112年7月1 日以後之初任公務人員，不包括已退休及現職人員", "我國為民國112年7月1日以後之初任公務人員重新建立退撫制度，採行確定提撥制，搭配設立個 人退休金專戶，並於其在職期間與政府共同按月撥繳退撫儲金費用", "為保障農民老年生活，於民國110年1月1日施行農民退休儲金條例，設立農民退休儲金個人專 戶，由農民與政府共同提繳退休儲金", "我國農民之老年經濟安全保障制度，由農民健康保險提供的老年農民福利津貼，以及農民退休 儲金共構而成"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:34+00:00", "source_pdf_sha1": "c98749f6e262", "answer_pdf_sha1": "d120e8b33bc5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "405", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "社會行政"}'::jsonb, NULL),
  ('pukao-64311456-moex-00260', 'pukao-64311456', 'pukao-64311456-moex-112-e718b90b', 'sub-pukao-64311456-02', NULL, 'single_choice', '兒童及少年福利與權益保障法第14條規定，胎兒出生後7日內，下列何種身分者，應將其出生之相 關資料通報衛生主管機關備查？', '["父母或監護人", "村（里）幹事", "戶政人員", "接生人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:34+00:00", "source_pdf_sha1": "c98749f6e262", "answer_pdf_sha1": "d120e8b33bc5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "405", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "社會行政"}'::jsonb, NULL),
  ('pukao-64311456-moex-00261', 'pukao-64311456', 'pukao-64311456-moex-112-e718b90b', 'sub-pukao-64311456-02', NULL, 'single_choice', '根據兒童及少年性剝削防制條例的規定，直轄市、縣（市）主管機關得令遭受性剝削或疑似遭受 性剝削之兒童或少年之父母、監護人或其他實際照顧之人，接受多少時數之親職教育輔導，並得 實施家庭處遇計畫？', '["10小時以上50小時以下", "8小時以上50小時以下", "6小時以上50小時以下", "4小時以上50小時以下"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:34+00:00", "source_pdf_sha1": "c98749f6e262", "answer_pdf_sha1": "d120e8b33bc5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "405", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "社會行政"}'::jsonb, NULL),
  ('pukao-64311456-moex-00262', 'pukao-64311456', 'pukao-64311456-moex-112-e718b90b', 'sub-pukao-64311456-02', NULL, 'single_choice', '依家庭暴力防治法的規定，家庭暴力的被害人得向法院聲請保護令，而且，如果被害人為未成年 人、身心障礙者或因故難以委任代理人者，法律有規定特定的人得為其向法院聲請之。請問這些 特定的人，不包括下列何者？', '["其三親等以內之姻親", "其三親等以內之血親", "其學校老師", "其法定代理人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:34+00:00", "source_pdf_sha1": "c98749f6e262", "answer_pdf_sha1": "d120e8b33bc5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "405", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "社會行政"}'::jsonb, NULL),
